mapper.select:
SELECT a.id, a.store_id, s.store_name, a.product_id, p.product_name, p.product_code, a.lot_number, a.alert_type, a.priority, a.status, a.message, a.threshold_value, a.current_value, a.detected_at, a.create_time, a.update_time FROM retail_alert a LEFT JOIN retail_store s ON a.store_id = s.id LEFT JOIN retail_product p ON a.product_id = p.id
AND a.store_id = #{query.storeId}
AND a.product_id = #{query.productId}
AND a.lot_number LIKE CONCAT('%', #{query.lotNumber}, '%')
AND a.alert_type = #{query.alertType}
AND a.priority = #{query.priority}
AND a.status = #{query.status}
AND a.detected_at >= #{query.detectedAtStart}
AND a.detected_at <= #{query.detectedAtEnd}
ORDER BY CASE a.priority WHEN 'P1' THEN 1 WHEN 'P2' THEN 2 WHEN 'P3' THEN 3 WHEN 'P4' THEN 4 ELSE 5 END, a.detected_at DESC

SELECT EXISTS(
    SELECT 1 FROM retail_alert
    WHERE store_id = #{storeId}
    AND product_id = #{productId}

        AND lot_number = #{lotNumber}


        AND (lot_number IS NULL OR lot_number = '')

    AND alert_type = #{alertType}
    AND status NOT IN ('RESOLVED', 'CLOSED')
)
